28	const CLAIM_DEDUCTIBLE = 100;
29	const CAP_MULTIPLIER = 2;
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	const COMPONENT_BLOCK_SIZE = 3;
33	const COMPONENT_BLOCK_PRICE = 60;
34	
35	interface Item {
36	  type: string;
37	  cursed?: boolean;
38	  enchantment?: number;
39	}
40	
41	interface QuoteStep {
42	  op: "quote";
43	  items: Item[];
44	}
45	
46	interface ClaimStep {
47	  op: "claim";
48	  policy: number;
49	  incident: { cause: string; damages: { type: string; amount: number }[] };
50	}
51	
52	type Step = QuoteStep | ClaimStep;
53	
